def choose_cost_model(traffic_pattern, needs_reserved_latency, needs_custom_host):
    # No prices are embedded; this only selects the billing shape to evaluate.
    if needs_custom_host:
        return "managed compute: VM size * instance count * hours"
    if needs_reserved_latency or traffic_pattern == "steady_high_volume":
        return "provisioned: required PTUs * reservation duration"
    return "standard or serverless: input and output usage such as tokens"

print(choose_cost_model("bursty", False, False))
